#[napi]
pub fn normalize_payload(input: String) -> Result<String> {
    let decoded = urlencoding::decode(&input)
        .map_err(|e| Error::from_reason(e.to_string()))?;

    let canonical = decoded
        .trim()
        .to_lowercase();

    Ok(canonical)
}
